<template>
    <div class="monitor-preview">
        <div class="preview-header" v-if="result.metadata">
            <h4>{{ result.metadata.folio }}</h4>
            <small>
                {{ result.metadata.fecha }} |
                {{ result.metadata.imageType }}
            </small>
        </div>

        <div v-if="!result || !result.canvas" class="empty-preview">
            No hay imagen generada para mostrar
        </div>

        <div v-else ref="canvasContainer" class="canvas-container"></div>
    </div>
</template>

<script>
export default {
    name: 'MonitoringScenePreview',
    props: {
        result: {
            type: Object,
            default: null
        }
    },
    watch: {
        result: {
            immediate: true,
            deep: true,
            handler(v) {
                console.log(v)
                this.renderCanvas();
            }
        }
    },
    mounted() {
        console.log(this.$props)
        this.renderCanvas();
    },
    methods: {
        renderCanvas() {
            this.$nextTick(() => {
                const container = this.$refs.canvasContainer;
                if (!container) return;

                container.innerHTML = '';

                if (this.result && this.result.canvas) {
                    container.appendChild(this.result.canvas);
                }
            });
        }
    }
};
</script>

<style scoped>
.monitor-preview {
    width: 100%;
}

.preview-header {
    margin-bottom: 10px;
}

.canvas-container {
    width: 100%;
    min-height: 200px;
    border: 1px solid #ddd;
    border-radius: 6px;
    overflow: auto;
    background: #fafafa;
    padding: 8px;
}

.empty-preview {
    padding: 20px;
    border: 1px dashed #bbb;
    border-radius: 6px;
    color: #666;
}
</style>